# 初始化后，切换为GPS Only模式
success, cmd = gps.set_system_mode(gps.MODE_GPS_ONLY)
if success:
    print(f"切换为GPS Only模式成功，发送指令:{cmd}")
else:
    print("切换模式失败")

# 延时5秒后，切换回BDS+GPS双模模式
time.sleep(5)
success, cmd = gps.set_system_mode(gps.MODE_BDS_GPS)
if success:
    print(f"切换为BDS+GPS模式成功，发送指令:{cmd}")
else:
    print("切换模式失败")
